"use strict";let submitted=!1;const QUIZ_KEYS=["quiz_clientele","quiz_volume","quiz_connexion","quiz_current_step"];function clearQuizSession(){QUIZ_KEYS.forEach(k=>sessionStorage.removeItem(k))}async function submitLead(payload){const resp=await fetch("/api/submit-lead",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)}),data=await resp.json().catch(()=>({}));if(!resp.ok||!data.ok)throw new Error(`HTTP ${resp.status}`);return data.token}function showFormError(msg){const el=document.getElementById("form-error");el&&(el.textContent=msg,el.classList.add("visible"))}function clearFormError(){const el=document.getElementById("form-error");el&&(el.textContent="",el.classList.remove("visible"))}function initForm(){const form=document.getElementById("lead-form"),submitBtn=document.getElementById("submit-btn"),successEl=document.getElementById("form-success");form&&form.addEventListener("submit",async e=>{if(e.preventDefault(),submitted)return;clearFormError();const firstName=document.getElementById("first-name")?.value.trim()||"",email=document.getElementById("email")?.value.trim()||"",gdpr=document.getElementById("gdpr")?.checked;if(!firstName)return void showFormError("Veuillez entrer votre prénom.");if(!email||!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email))return void showFormError("Veuillez entrer une adresse e-mail valide.");if(!gdpr)return void showFormError("Vous devez accepter la politique de confidentialité (RGPD) pour continuer.");submitBtn.disabled=!0,submitBtn.textContent="Envoi en cours…";const payload={first_name:firstName,email:email,gdpr:gdpr,clientele:sessionStorage.getItem("quiz_clientele")||"",statut:"",volume:sessionStorage.getItem("quiz_volume")||"",connexion:sessionStorage.getItem("quiz_connexion")||""};try{const token=await submitLead(payload);submitted=!0,clearQuizSession(),successEl&&(successEl.textContent="✓ Merci ! Votre plan d'action vous a été envoyé par e-mail.",successEl.classList.add("show")),window.location.href=`/api/download-pdf?token=${encodeURIComponent(token)}`,setTimeout(()=>{window.location.href="index.html"},2500)}catch{submitBtn.disabled=!1,submitBtn.textContent="Obtenir mon plan d'action (PDF)",showFormError("Une erreur est survenue. Veuillez réessayer dans quelques instants.")}})}function initB2CResult(){"b2c"===sessionStorage.getItem("quiz_clientele")&&(document.getElementById("results-banner-default")?.setAttribute("hidden",""),document.getElementById("results-banner-b2c")?.removeAttribute("hidden"),document.getElementById("b2c-message")?.removeAttribute("hidden"),document.getElementById("partners-intro")?.setAttribute("hidden",""),document.getElementById("articles-grid")?.setAttribute("hidden",""))}const OTHER_SOFTWARE={name:"Votre logiciel actuel",icon:"assets/images/autre.webp",badge:"Non certifié PDP",desc:"Votre logiciel actuel n'est pas certifié PDP pour la réforme 2026. Découvrez ci-dessous nos solutions certifiées pour rester conforme sans rupture de service.",href:"#",ctaText:"Comparer les solutions →"},SOFTWARE_CATALOG={pennylane:{name:"Pennylane",icon:"assets/images/pennylane.webp",badge:"Certifié PDP",desc:"Comptabilité et facturation électronique tout-en-un, pensée pour les TPE/PME.",href:"#"},sage:{name:"Sage",icon:"assets/images/sage.webp",badge:"Certifié PDP",desc:"Solution éprouvée pour la gestion comptable et la conformité 2026.",href:"#"},quickbooks:{name:"QuickBooks",icon:"assets/images/quickbooks.webp",badge:"Partenaire",desc:"Facturation simple et automatisée, idéale pour démarrer rapidement.",href:"#"},cegid:{name:"Cegid",icon:"assets/images/cegid.webp",badge:"Certifié PDP",desc:"Plateforme complète de comptabilité et facturation, des PME aux grands groupes.",href:"#"}};function shuffled(arr){const a=arr.slice();for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}function buildCardHTML(key,isCurrent){const sw="autre"===key?OTHER_SOFTWARE:SOFTWARE_CATALOG[key],badge=isCurrent&&"autre"!==key?"Votre logiciel actuel":sw.badge,desc=isCurrent&&"autre"!==key?`Bonne nouvelle : vous utilisez déjà ${sw.name}. Profitez de la mise à niveau ${sw.name} certifiée PDP pour rester conforme à la réforme 2026, sans changer d'outil.`:sw.desc,ctaText=sw.ctaText||(isCurrent?"Mettre à niveau →":"Découvrir →");return`<div class="article-card partner-card" data-software="${key}">\n              <span class="partner-badge">${badge}</span>\n              <div class="article-header">\n                <img src="${sw.icon}" alt="" class="article-icon" aria-hidden="true" loading="lazy" />\n                <h3 class="article-title">${sw.name}</h3>\n              </div>\n              <p class="article-desc">${desc}</p>\n              <a href="${sw.href}" class="btn-cta partner-discover-btn" target="_blank" rel="noopener sponsored">${ctaText}</a>\n            </div>`}function buildRecommendations(){const grid=document.getElementById("articles-grid");if(!grid)return;const connexion=sessionStorage.getItem("quiz_connexion"),allKeys=Object.keys(SOFTWARE_CATALOG);if("autre"===connexion){const orderedKeys=["autre",...shuffled(allKeys).slice(0,2)];return void(grid.innerHTML=orderedKeys.map(key=>buildCardHTML(key,"autre"===key)).join(""))}const hasMatch=Object.prototype.hasOwnProperty.call(SOFTWARE_CATALOG,connexion),orderedKeys=hasMatch?[connexion,...shuffled(allKeys.filter(k=>k!==connexion)).slice(0,2)]:shuffled(allKeys).slice(0,3);grid.innerHTML=orderedKeys.map(key=>buildCardHTML(key,hasMatch&&key===connexion)).join("")}function init(){initB2CResult(),buildRecommendations(),initForm()}document.addEventListener("DOMContentLoaded",init);